mapper.select:
SELECT 
FROM de_energy_flow
WHERE enterprise_id = #{enterpriseId}
  AND audit_year = #{auditYear}
  AND deleted = 0
ORDER BY seq_no ASC, id ASC

mapper.update:
UPDATE de_energy_flow
SET deleted = 1, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
WHERE enterprise_id = #{enterpriseId}
  AND audit_year = #{auditYear}
  AND deleted = 0

UPDATE de_energy_flow
SET deleted = 1, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND enterprise_id = #{enterpriseId}
  AND deleted = 0
